parameters.jsCode:
const comp = $('Loop competitors').item.json;
const cap = (s, n) => (s || '').toString().replace(/\s+/g, ' ').slice(0, n);
let corpus = 'COMPETITOR: ' + comp.name + ' | aliases: ' + comp.aliases.join(', ') + ' | domain: ' + comp.domain + '\nPROFILE: ' + (comp.profile||'') + '\n\n=== GOOGLE RESULTS (retrieved search pages; title/url/snippet) ===\n';
try {
  const g = $('Apify: Google search').all();
  for (const it of g) {
    const r = it.json;
    if (r.organicResults) { for (const o of r.organicResults.slice(0, 15)) corpus += '- ' + cap(o.title, 150) + ' | ' + o.url + ' | ' + cap(o.description, 250) + '\n'; }
  }
} catch (e) { corpus += '(google source unavailable)\n'; }
corpus += '\n=== COMPETITOR WEBSITE PAGES ===\n';
try {
  const s = $('Apify: site crawl').all();
  for (const it of s.slice(0, 10)) { const p = it.json; if (p.url) corpus += '\n--- PAGE: ' + p.url + ' ---\n' + cap(p.text || p.markdown, 2600) + '\n'; }
} catch (e) { corpus += '(site source unavailable)\n'; }
corpus = corpus.slice(0, 100000);
return [{ json: { competitor: comp.name, corpus } }];

const comp = $('Loop competitors').item.json;
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
let out = [];
const blocks = ($json && Array.isArray($json.content)) ? $json.content : [];
const tb = blocks.find(b => b && b.type === 'text' && typeof b.text === 'string');
let txt = tb ? tb.text : '';
let data = { confirmed: [], unverified: [] };
let bad = false;
try {
  const m = txt.match(/\{[\s\S]*\}/);
  if (m) { data = JSON.parse(m[0]); } else if (txt.trim().length > 0) { bad = true; }
} catch (e) { bad = true; }
if (bad) {
  out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: 'PARSE ERROR', Year: '', Hint: '', Reason: 'model output not JSON: ' + String(txt).slice(0, 160), ScannedAt: now } });
}
for (const r of (data.confirmed || [])) { out.push({ json: { _sheet: 'confirmed', Competitor: comp.name, Event: r.event || '', Year: String(r.year || ''), Status: r.status || '', Role: r.role || '', Evidence: r.evidence_quote || '', Confidence: r.confidence || '', SourceURL: r.source_url || '', ScannedAt: now } }); }
for (const r of (data.unverified || [])) { out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: r.event || '', Year: String(r.year || ''), Hint: r.hint || '', Reason: r.reason || '', ScannedAt: now } }); }
if (out.length === 0) { out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: '(no signals found)', Year: '', Hint: '', Reason: 'no event signals in corpus', ScannedAt: now } }); }
return out;

const j = $('Assemble corpus').item.json;
const c = j.corpus || '';
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const out = [];
for (let i = 0; i < c.length && i < 135000; i += 45000) {
  out.push({ json: { Competitor: j.competitor, Part: String(Math.floor(i / 45000) + 1), Corpus: c.slice(i, i + 45000), ScannedAt: now } });
}
if (out.length === 0) { out.push({ json: { Competitor: j.competitor, Part: '1', Corpus: '(empty corpus)', ScannedAt: now } }); }
return out;
